import{_ as e,c as a,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"平台与集成: 多协议统一网关 | Antigravity Manager","description":"学习 Antigravity Manager 的多平台集成方法。支持 OpenAI、Anthropic、Gemini 等协议，统一本地 API 网关访问。","frontmatter":{"title":"平台与集成: 多协议统一网关 | Antigravity Manager","sidebarTitle":"Platforms","subtitle":"平台与集成: 多协议统一网关","description":"学习 Antigravity Manager 的多平台集成方法。支持 OpenAI、Anthropic、Gemini 等协议，统一本地 API 网关访问。","order":2},"headers":[],"relativePath":"lbjlaq/Antigravity-Manager/platforms/index.md","filePath":"lbjlaq/Antigravity-Manager/platforms/index.md"}'),o={name:"lbjlaq/Antigravity-Manager/platforms/index.md"};function n(d,t,l,s,c,p){return r(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="platforms-integrations" tabindex="-1">Platforms &amp; Integrations <a class="header-anchor" href="#platforms-integrations" aria-label="Permalink to &quot;Platforms &amp; Integrations&quot;">​</a></h1><p>Antigravity Tools&#39; core capability is converting protocols from multiple AI platforms into a unified local API gateway. This chapter details the integration methods, compatibility boundaries, and best practices for each protocol.</p><h2 id="in-this-chapter" tabindex="-1">In This Chapter <a class="header-anchor" href="#in-this-chapter" aria-label="Permalink to &quot;In This Chapter&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tutorial</th><th>Description</th></tr></thead><tbody><tr><td><a href="./openai/">OpenAI Compatible API</a></td><td>Implementation strategy for <code>/v1/chat/completions</code> and <code>/v1/responses</code>, enabling seamless OpenAI SDK integration</td></tr><tr><td><a href="./anthropic/">Anthropic Compatible API</a></td><td>Key contracts for <code>/v1/messages</code> and Claude Code, supporting core features like chain-of-thought and system prompts</td></tr><tr><td><a href="./gemini/">Gemini Native API</a></td><td><code>/v1beta/models</code> and Google SDK endpoint integration, supporting <code>x-goog-api-key</code> compatibility</td></tr><tr><td><a href="./imagen/">Imagen 3 Image Generation</a></td><td>Automatic mapping of OpenAI Images parameters <code>size</code>/<code>quality</code>, supporting arbitrary aspect ratios</td></tr><tr><td><a href="./audio/">Audio Transcription</a></td><td>Limitations of <code>/v1/audio/transcriptions</code> and handling large payloads</td></tr><tr><td><a href="./mcp/">MCP Endpoints</a></td><td>Expose Web Search/Reader/Vision as callable tools</td></tr><tr><td><a href="./cloudflared/">Cloudflared Tunnel</a></td><td>One-click secure exposure of local API to public internet (not secure by default)</td></tr></tbody></table><h2 id="recommended-learning-path" tabindex="-1">Recommended Learning Path <a class="header-anchor" href="#recommended-learning-path" aria-label="Permalink to &quot;Recommended Learning Path&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Recommended Order</p><ol><li><strong>Learn the protocol you use first</strong>: If you use Claude Code, start with <a href="./anthropic/">Anthropic Compatible API</a>; if you use OpenAI SDK, start with <a href="./openai/">OpenAI Compatible API</a></li><li><strong>Then learn Gemini Native</strong>: Understand direct Google SDK integration</li><li><strong>Learn extended features as needed</strong>: Image generation, audio transcription, MCP tools</li><li><strong>Finally learn tunneling</strong>: Only look at <a href="./cloudflared/">Cloudflared Tunnel</a> when you need public exposure</li></ol></div><p><strong>Quick Selection</strong>:</p><table tabindex="0"><thead><tr><th>Your Scenario</th><th>Start With</th></tr></thead><tbody><tr><td>Using Claude Code CLI</td><td><a href="./anthropic/">Anthropic Compatible API</a></td></tr><tr><td>Using OpenAI Python SDK</td><td><a href="./openai/">OpenAI Compatible API</a></td></tr><tr><td>Using Google Official SDK</td><td><a href="./gemini/">Gemini Native API</a></td></tr><tr><td>Need AI Image Generation</td><td><a href="./imagen/">Imagen 3 Image Generation</a></td></tr><tr><td>Need Speech-to-Text</td><td><a href="./audio/">Audio Transcription</a></td></tr><tr><td>Need Web Search/Reading</td><td><a href="./mcp/">MCP Endpoints</a></td></tr><tr><td>Need Remote Access</td><td><a href="./cloudflared/">Cloudflared Tunnel</a></td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Before Starting</p><ul><li>Completed <a href="./../start/installation/">Installation &amp; Upgrades</a></li><li>Completed <a href="./../start/add-account/">Add Accounts</a></li><li>Completed <a href="./../start/proxy-and-first-client/">Start Local Reverse Proxy</a> (at least able to access <code>/healthz</code>)</li></ul></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this chapter, you can continue learning:</p><ul><li><a href="./../advanced/">Advanced Configuration</a>: Model routing, quota management, high-availability scheduling, and other advanced features</li><li><a href="./../faq/">FAQ</a>: Troubleshooting guide for 401/404/429 and other errors</li></ul>',13)])])}const u=e(o,[["render",n]]);export{m as __pageData,u as default};
